#include "Shelf.h"#include <iostream>#include <stdexcept>#include <utility>using namespace std;Item* Shelf::operator[](int index) {    if (index < 0 || index >= MAX_COMPARTMENT_SIZE) {        throw out_of_range("Invalid compartment index.\n");    }    return compartment[index].get();}bool Shelf::isCompartmentEmpty(int index) const {    if (index < 0 || index >= MAX_COMPARTMENT_SIZE) {        throw out_of_range("Invalid compartment index.\n");    }    return compartment[index] == nullptr;}void Shelf::placeItem(int index, unique_ptr<Item> item) {    if (index < 0 || index >= MAX_COMPARTMENT_SIZE) {        throw out_of_range("Invalid compartment index.\n");    }    if (item == nullptr) {        cout << "Error: Cannot place a null item." << endl;        return;    }    if (!isCompartmentEmpty(index)) {        cout << "Error: Compartment is already occupied." << endl;        return;    }    compartment[index] = std::move(item);}void Shelf::clearCompartment(int index) {    if (index < 0 || index >= MAX_COMPARTMENT_SIZE) {        throw out_of_range("Invalid compartment index.\n");    }    if (isCompartmentEmpty(index)) {        cout << "Error: Compartment is already empty." << endl;        return;    }    compartment[index] = nullptr;}void Shelf::swapCompartments(int index1, Shelf& otherShelf, int index2) {    if (index1 < 0 || index1 >= MAX_COMPARTMENT_SIZE ||        index2 < 0 || index2 >= MAX_COMPARTMENT_SIZE) {        throw out_of_range("Invalid compartment index.\n");        }    if (compartment[index1] == nullptr || otherShelf.compartment[index2] == nullptr) {        throw out_of_range("Cannot swap because one or both compartments are empty.\n");    }    swap(compartment[index1], otherShelf.compartment[index2]);}